codeComparison.old:
/* Hard-coded colors — change means updating many places */
.card { background-color: white; }
.button { background-color: #667eea; }
h1 { color: #667eea; }

codeComparison.new:
/* Light theme */
:root {
  --primary: #667eea;
  --bg: #f9f9f9;
  --card-bg: #ffffff;
  --text: #333;
}

/* Dark theme */
[data-theme="dark"] {
  --primary: #8b9de8;
  --bg: #1a1a1a;
  --card-bg: #2a2a2a;
  --text: #f0f0f0;
}

/* Same CSS, different look! */
.card { background: var(--card-bg); }
.button { background: var(--primary); }
h1 { color: var(--primary); }

codeComparison.old:
/* Simple hover — just changes color */
.card:hover {
  background-color: blue;
}

codeComparison.new:
/* 3D card flip */
.card-container {
  perspective: 1000px;
}
.card-flip {
  transform-style: preserve-3d;
  transition: transform 0.6s;
}
.card-container:hover .card-flip {
  transform: rotateY(180deg);
}
.card-front, .card-back {
  backface-visibility: hidden;
}
.card-back {
  transform: rotateY(180deg);
}

codeComparison.old:
/* Flat card — no depth */
.card {
  background: white;
  border: 1px solid #ddd;
}

codeComparison.new:
/* Glassmorphism card */
.glass-card {
  background: rgba(255, 255, 255, 0.1);
  backdrop-filter: blur(10px);
  -webkit-backdrop-filter: blur(10px);
  border-radius: 20px;
  border: 1px solid rgba(255, 255, 255, 0.2);
  padding: 40px;
  box-shadow: 0 8px 32px rgba(0, 0, 0, 0.1);
}
